// §B — the trailing-`TypeAdapter` overload on the column factories where only
// the no-adapter form was previously fixtured. The `tLedgerEntry` fixture
// carries one adapter per factory:
//   - entry_no: `autogeneratedPrimaryKey('int', plusOffsetAdapter)` — the
//     DB-generated id surfaces read +1000, and a WHERE operand is shifted -1000.
//   - amount:  `columnWithDefaultValue('int', scaledTenthAdapter)` over a DB
//     DEFAULT 100 — read ÷10, write ×10.
//   - memo:    `optionalColumnWithDefaultValue('int', scaledTenthAdapter)` over
//     a DB DEFAULT 50.
//   - tag:     `optionalVirtualColumnFromFragment('string', bracketAdapter)` —
//     no DB column; the fragment value is read wrapped in [...].
// Seed: one row, amount raw 250 (→25), memo raw 70 (→7), entry_no 1 (→1001).

import { afterAll, beforeAll, beforeEach, describe, expect, test } from '../../../../lib/testRunner.js'
import { assertType, type Exact } from '../../../../lib/assertType.js'
import { tLedgerEntry } from '../../domain/connection.js'
import { ctx } from './setup.js'

describe(ctx.label, () => {
    beforeAll(() => ctx.up(), ctx.timeoutMs)
    afterAll(() => ctx.down(), ctx.timeoutMs)
    beforeEach(() => { ctx.reset() })

    test('column-factory-adapter-overloads-read-path-and-pk-where-operand', async () => {
        // One read exercises every factory's read adapter: entry_no +1000
        // (plusOffsetAdapter), amount/memo ÷10 (scaledTenthAdapter), tag
        // bracketed (bracketAdapter). The WHERE filters by the OFFSET id 1001,
        // so the plusOffsetAdapter write transform shifts the bound operand to
        // the raw 1 — proving the adapter overload propagates on both paths.
        const expected = { entryNo: 1001, amount: 25, memo: 7, tag: '[LED]' }
        ctx.mockNext({ entryNo: 1, amount: 250, memo: 70, tag: 'LED' })
        const row = await ctx.conn.selectFrom(tLedgerEntry)
            .where(tLedgerEntry.entryNo.equals(1001))
            .select({
                entryNo: tLedgerEntry.entryNo,
                amount:  tLedgerEntry.amount,
                memo:    tLedgerEntry.memo,
                tag:     tLedgerEntry.tag,
            })
            .executeSelectOne()

        expect(ctx.lastSql).toMatchInlineSnapshot(`"select entry_no as entryNo, amount as amount, memo as memo, upper('led') as tag from ledger_entry where entry_no = @0"`)
        expect(ctx.lastParams).toMatchInlineSnapshot(`
          [
            1,
          ]
        `)
        assertType<Exact<typeof row, { entryNo: number; amount: number; memo?: number; tag?: string }>>()
        expect(row).toEqual(expected)
    })

    test('default-value-column-adapter-scales-the-bound-param-on-write', async () => {
        // `columnWithDefaultValue('int', scaledTenthAdapter)` runs its write
        // transform on the insert operand: amount 15 binds the scaled 150,
        // memo 8 binds 80. (entry_no is autogenerated, omitted from the insert.)
        ctx.mockNext(1)
        await ctx.withRollback(async () => {
            const affected = await ctx.conn.insertInto(tLedgerEntry)
                .values({ amount: 15, memo: 8 })
                .executeInsert()

            expect(ctx.lastSql).toMatchInlineSnapshot(`"insert into ledger_entry (amount, memo) values (@0, @1)"`)
            expect(ctx.lastParams).toMatchInlineSnapshot(`
              [
                150,
                80,
              ]
            `)
            assertType<Exact<typeof affected, number>>()
            if (!ctx.realDbEnabled) expect(affected).toBe(1)
        })
    })

    test('autogen-pk-adapter-applies-on-the-returning-last-inserted-id-path', async () => {
        // `returningLastInsertedId()` reads the DB-generated entry_no back
        // through plusOffsetAdapter, so the returned id surfaces +1000. The
        // returned value is the DB id (which advances per insert and is NOT
        // rewound by rollback on every engine), so it is asserted mock-only;
        // the INSERT SQL + the offset-applied read are the real-DB invariant.
        await ctx.withRollback(async () => {
            ctx.mockNext(2)
            const newId = await ctx.conn.insertInto(tLedgerEntry)
                .defaultValues()
                .returningLastInsertedId()
                .executeInsert()

            expect(ctx.lastSql).toMatchInlineSnapshot(`"insert into ledger_entry output inserted.entry_no default values"`)
            expect(ctx.lastParams).toMatchInlineSnapshot(`[]`)
            assertType<Exact<typeof newId, number>>()
            // mock-only: the real DB id advances across rollback tests, so its
            // exact value is non-deterministic; the +1000 offset is verified
            // here against the primed raw 2.
            if (!ctx.realDbEnabled) expect(newId).toBe(1002)
        })
    })

    test('default-value-columns-apply-db-default-read-through-the-adapter', async () => {
        // Inserting with all columns defaulted (`defaultValues()`) lets the DB
        // apply DEFAULT 100 / 50; reading the new row back (filtered by the
        // scaled amount, which is deterministic) surfaces amount 10 and memo 5
        // through the scaledTenthAdapter.
        await ctx.withRollback(async () => {
            ctx.mockNext(1)
            await ctx.conn.insertInto(tLedgerEntry)
                .defaultValues()
                .executeInsert()

            const expected = { amount: 10, memo: 5 }
            ctx.mockNext({ amount: 100, memo: 50 })
            const row = await ctx.conn.selectFrom(tLedgerEntry)
                .where(tLedgerEntry.amount.equals(10))
                .select({
                    amount: tLedgerEntry.amount,
                    memo:   tLedgerEntry.memo,
                })
                .executeSelectOne()

            expect(ctx.lastSql).toMatchInlineSnapshot(`"select amount as amount, memo as memo from ledger_entry where amount = @0"`)
            expect(ctx.lastParams).toMatchInlineSnapshot(`
              [
                100,
              ]
            `)
            assertType<Exact<typeof row, { amount: number; memo?: number }>>()
            expect(row).toEqual(expected)
        })
    })

    test('optional-default-value-column-adapter-accepts-explicit-null', async () => {
        // `optionalColumnWithDefaultValue` accepts an explicit null (overriding
        // the DB DEFAULT); the scaledTenthAdapter passes null through unchanged
        // on write, and the read surfaces it as an absent (undefined) field.
        // The row is read back by its scaled amount (deterministic).
        await ctx.withRollback(async () => {
            ctx.mockNext(1)
            await ctx.conn.insertInto(tLedgerEntry)
                .values({ amount: 12, memo: null })
                .executeInsert()

            const expected = { amount: 12, memo: undefined }
            ctx.mockNext({ amount: 120, memo: null })
            const row = await ctx.conn.selectFrom(tLedgerEntry)
                .where(tLedgerEntry.amount.equals(12))
                .select({
                    amount: tLedgerEntry.amount,
                    memo:   tLedgerEntry.memo,
                })
                .executeSelectOne()

            expect(ctx.lastSql).toMatchInlineSnapshot(`"select amount as amount, memo as memo from ledger_entry where amount = @0"`)
            expect(ctx.lastParams).toMatchInlineSnapshot(`
              [
                120,
              ]
            `)
            assertType<Exact<typeof row, { amount: number; memo?: number }>>()
            expect(row).toEqual(expected)
        })
    })
})
